        const fileNameLower = file.name.toLowerCase();
        const fileBuffer = await file.arrayBuffer();
        let extractedText = '';

        if (fileNameLower.endsWith('.pdf')) {
             if (!pdfjsLib) throw new Error("Biblioteca PDF não carregada.");
             const loadingTask = pdfjsLib.getDocument(new Uint8Array(fileBuffer));
             const pdf = await loadingTask.promise;
             const totalPages = pdf.numPages;
             const textParts: string[] = [];

             for (let i = 1; i <= totalPages; i++) {
                 await new Promise(resolve => setTimeout(resolve, 0));
                 if (setParsingProgress) {
                    setParsingProgress({ 
                        current: i, 
                        total: totalPages, 
                        label: `Lendo página ${i} de ${totalPages}...` 
                    });
                 }
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const items = textContent.items as any[];
                 const lineMap: { [key: number]: any[] } = {};
                 items.forEach(item => {
                     const y = Math.round(item.transform[5]);
                     if (!lineMap[y]) lineMap[y] = [];
                     lineMap[y].push(item);
                 });
                 const sortedY = Object.keys(lineMap).map(Number).sort((a, b) => b - a);
                 sortedY.forEach(y => {
                     const sortedItems = lineMap[y].sort((a, b) => a.transform[4] - b.transform[4]);
                     const lineText = sortedItems.map(it => it.str).join(' ');
                     if (lineText.trim()) textParts.push(lineText);
                 });
             }
             extractedText = textParts.join('\n');
        } else if (fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls')) {
            if (!XLSX) throw new Error("Excel lib missing");
            const workbook = XLSX.read(new Uint8Array(fileBuffer), { type: 'array' });
            const worksheet = workbook.Sheets[workbook.SheetNames[0]];

            // Fidelidade Total: Obtém os dados sem filtragem de colunas ou linhas intermediárias.
            // defval: '' garante que células vazias sejam mantidas como strings vazias para join(';')
            const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: '' }) as any[][];

            extractedText = jsonData
                .map(row => row.join(';'))
                .filter(line => line.replace(/;/g, '').trim().length > 0) // Remove apenas linhas 100% vazias (sem dados nem delimitadores preenchidos)
                .join('\n');
        } else {
            extractedText = new TextDecoder('utf-8').decode(fileBuffer);
        }

        console.log(`[Ingestion:DONE] Extração concluída. Amostra: ${extractedText.substring(0, 30)}`);
        await onFileUpload(extractedText, file.name, file);

    } catch (error: any) {
        console.error("[Uploader] Fail:", error);
        alert(`Erro ao carregar arquivo: ${error.message}`);
    } finally {
        isBusyRef.current = false;
        setIsParsing(false);
        if (setParsingProgress) setParsingProgress(null);
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (!disabled && !isParsing && !isBusyRef.current) fileInputRef.current?.click();
  };

  if (customTrigger) {
      return (
          <div className="flex-shrink-0">
              <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept={SUPPORTED_FORMATS} />
              {customTrigger({ onClick: handleClick, disabled: disabled || isParsing, isParsing })}
          </div>
      );
  }

  return (
    <div className="flex-shrink-0">
      <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept={SUPPORTED_FORMATS} />
      <button type="button" onClick={handleClick} disabled={disabled || isParsing} className={`group inline-flex items-center justify-center space-x-1.5 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-wide transition-all ${disabled ? 'bg-slate-100 text-slate-400' : 'text-white bg-emerald-600 hover:bg-emerald-500 shadow-sm'}`}>
         {isParsing ? <><svg className="animate-spin h-3 w-3 text-white mr-1" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg><span>Extraindo...</span></> : <><UploadIcon className="w-3 h-3" /><span>{title}</span></>}
      </button>
    </div>
  );
});

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V14 - NORMALIZAÇÃO ESTRUTURAL FIEL)
 * -------------------------------------------------------
 * Mantém a integridade das linhas mesmo em arquivos com delimitadores puros.
 */
export const IngestionOrchestrator = {
    /**
     * Normalização: Remove espaços em branco nas pontas e filtra apenas linhas 100% vazias.
     * Preserva linhas que possuem delimitadores (ex: ";;;") para não quebrar o mapeamento.
     */
    normalizeRawContent(content: string): string {
        if (!content) return "";

        return content
            .split(/\r?\n/)
            .map(line => line.trimEnd())
            // Filtra apenas se a linha estiver vazia após o trim (não remove ";;;")
            .filter(l => l.trim().length > 0)
            .join('\n');
    },

    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<any> {
        const fileNameLower = file.name.toLowerCase();

        // NORMALIZAÇÃO FIEL
        const processedContent = this.normalizeRawContent(content);
        const fingerprint = Fingerprinter.generate(processedContent);

        console.log(`[Pipeline:INGESTION] Processando: ${file.name} | Amostra Normalizada: ${processedContent.substring(0, 30)}`);

        const result = await StrategyEngine.process(
            file.name, 
            { __rawText: processedContent, __source: 'file' }, 
            models, 
            globalKeywords
        );

        return {
            source: 'upload',
            transactions: result.transactions || [],
            status: result.status,
            fileName: result.fileName || file.name,
            fingerprint: result.fingerprint || fingerprint || { columnCount: 0 },
            preview: result.preview || processedContent.substring(0, 500),
            strategyUsed: result.strategyName
        };
    },

    async processVirtualData(
        sourceName: string,
        transactions: Transaction[],
        globalKeywords: string[]
    ): Promise<any> {
        return {
            source: 'virtual',
            transactions: transactions,
            strategyUsed: `Virtual:${sourceName}`,
            fingerprint: { columnCount: 3 }
        };
    }
};

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { generateFingerprint } from '../services/processingService';
import { FileModel } from '../types';
import { useUI } from '../contexts/UIContext';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);
    const { showToast } = useUI();

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    const sheet = wb.Sheets[wb.SheetNames[0]];
                    // Fidelidade: defval: '' e header: 1 preservam a grade original
                    const rawData = XLSX.utils.sheet_to_json<any[]>(sheet, { header: 1, defval: '' });

                    // Filtra apenas linhas 100% vazias para manter paridade com o uploader
                    loadedRows = rawData
                        .filter(row => row.join('').trim().length > 0)
                        .map(row => row.map(cell => String(cell || '').trim()));
                } 
                else {
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const normalized = IngestionOrchestrator.normalizeRawContent(content);
                        loadedRows = normalized.split('\n').map(line => line.split(';'));
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);
                    const sampleContentForFp = loadedRows.slice(0, 30).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContentForFp);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else {
                        setActiveMapping({
                            extractionMode: 'COLUMNS',
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no laboratório:", err);
                showToast("Erro ao ler estrutura do arquivo.", "error");
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, initialModel, showToast]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};
